#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Diagnose why the email-scaler isn't producing (exit-0-safe): service status + journal,
and a bounded manual run (BATCH=3) capturing stdout/exit -> scaler-diag.json."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error
def sh(c,t=100):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t); return (r.stdout+r.stderr).strip()
    except Exception as e: return "TO/ERR:%s"%e
out={"kind":"scaler_diag","ts":int(time.time())}
try:
    out["status"]=sh("systemctl status atlas-deepcrawl.service --no-pager -l 2>&1 | tail -18")
    out["journal"]=sh("journalctl -u atlas-deepcrawl.service -n 25 --no-pager 2>&1 | tail -25")
    out["execstart"]=sh("systemctl cat atlas-deepcrawl.service 2>&1 | grep -iE 'ExecStart|Environment|WorkingDir' | head")
    out["manual_run"]=sh("cd /opt/atlas && DEEPCRAWL_BATCH=3 timeout 90 /opt/atlas/venv/bin/python /opt/atlas/importers/atlas_email_deepcrawl.py 2>&1 | tail -25", t=110)
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    br="main"; api="https://api.github.com"; path="status/hetzner/scaler-diag.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"scaler_diag","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
